#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
    int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline char Get(){char ch=getchar();while(ch^'U'&&ch^'Z')ch=getchar();return ch;}
const int N=1e6+10;
int n,m,a[N],P[N],o1[N],o2[N],mm;bool opt[N];
struct BIT
{
    LL t[N];inline void add(int p,int v){while(p<=m+1)t[p]+=v,p+=(p&-p);}
    inline LL qry(int p){LL r=0;while(p)r+=t[p],p^=(p&-p);return r;}
}nm,sm;
inline int fnd(int k)
{
    int l=1,r=mm,res,mid;
    while(l<=r)P[mid=(l+r)>>1]<=k?(l=mid+1,res=mid):(r=mid-1);return res;
}
inline void debug()
{
    rep(1,10,i)printf("%d ",nm.qry(i)-nm.qry(i-1));puts("");
    rep(1,10,i)printf("%d ",sm.qry(i)-sm.qry(i-1));puts("");
}
int main()
{
    n=read();m=read();P[m+1]=0;
    rep(1,m,i){opt[i]=(Get()=='Z');o1[i]=read();P[i]=o2[i]=read();}
    std::sort(P+1,P+m+2);mm=m+1;//rep(1,m+1,i)printf("%d ",P[i]);puts("");
    nm.add(1,n);nm.add(2,-n);
    // printf("%d %d %d %d\n",fnd(0),fnd(1),fnd(2),fnd(3));
    rep(1,m+1,i)a[i]=1;
    // puts("QWQQWQWQ");
    // debug();
    rep(1,m,i)
    {
        int w=fnd(o2[i]);switch(opt[i])
        {
            case 0:
                sm.add(a[o1[i]],-P[a[o1[i]]]);sm.add(w,P[w]);
                nm.add(a[o1[i]]+1,1);nm.add(w+1,-1);a[o1[i]]=w;break;
            case 1:
                puts((o1[i]-nm.qry(w))*o2[i]<=sm.qry(w-1)?"TAK":"NIE");
        }
        // printf("%d %d:: \n",i,w);debug();
    }
    return 0;
}
